import{_ as t,o as e,c as a,a3 as i}from"./chunks/framework.BjwLbrw5.js";const d=JSON.parse('{"title":"О влиянии","description":"","frontmatter":{"title":"О влиянии","date":"2022-06-14T00:00:00.000Z"},"headers":[],"relativePath":"posts/2022-06-14-impact.md","filePath":"posts/2022-06-14-impact.md"}'),l={name:"posts/2022-06-14-impact.md"};function o(s,p,_,r,c,n){return e(),a("div",null,[...p[0]||(p[0]=[i("<p>Основной инструмент лидера команды или формального управленца это другие люди.</p><p>Добиться чего-либо от людей можно только через техники влияния.</p><p>Разделить техники влияния можно на две категории: варварские и цивилизованные.</p><p>Если с цивилизованными всё просто - аргументация и контр-аргументация. С варварскими всё немного сложнее. Их хотелось бы разобрать подробнее.</p><p>Варварские методы:</p><ul><li>угрозы, принуждение, моральное давление</li><li>манипуляции (лесть, ложь)</li><li>нападение: <ul><li>непрошенные советы</li><li>деструктивная критика</li><li>деструктивная констатация</li></ul></li></ul><p>Варварские методы действуют на эмоции, разжигают гнев, злобу, вызывают чувство вины и беспомощности.</p><p>Наиболее эффективный способ отбить нападение - психологическое айкидо.</p><p>Вдох, выдох, - &quot;Да, Игорь, возможно вы правы&quot;</p><p>В особо жарких ситуациях хорошо работает испорченная пластинка - повторять одну и ту же фразу пока человек не успокоится.</p><p>Также можно уточнить - а как бы человек принял решение в этой ситуации.</p><p>Если ваша позиция чуть сильнее - можно объяснить своё поведение личностными качествами.</p><p>В любом случае, важно сразу отбить атаку так, чтобы конфликт не дошёл до точки невозврата - неконтролируемых эмоций.</p><p>Ни в коем случае не оправдываться, не шутить и не говорить снисходительно - это тоже конфликтогены.</p>",14)])])}const u=t(l,[["render",o]]);export{d as __pageData,u as default};
